import React, { useState, useEffect } from 'react';
import { Link, useSearchParams, useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import { formatDisplayName } from '../utils/nameFormatter';
import { gamesAPI } from '../services/api';
import { showNotification } from '../assets/notifications';
import { mockGames, Game } from '../data/mockGames';

const Home: React.FC = () => {
  const [games, setGames] = useState<Game[]>([]);
  const [loading, setLoading] = useState(true);
  const [favorites, setFavorites] = useState<string[]>([]);
  const [searchParams] = useSearchParams();
  const [filters, setFilters] = useState({
    platform: '',
    region: '',
    priceRange: 'all'
  });
  const [searchQuery, setSearchQuery] = useState('');
  const navigate = useNavigate();
  const { state } = useAuth();

  // Get search query from URL
  const queryFromUrl = searchParams.get('query') || '';

  // Load favorites from localStorage
  useEffect(() => {
    const savedFavorites = JSON.parse(localStorage.getItem('favorites') || '[]');
    setFavorites(savedFavorites.map((game: Game) => game._id));
  }, []);

  const addToCart = (game: Game) => {
    if (!state.isAuthenticated) {
      alert('يجب تسجيل الدخول أولاً!');
      return;
    }

    // Add to cart logic here
    const cart = JSON.parse(localStorage.getItem('cart') || '[]');
    cart.push(game);
    localStorage.setItem('cart', JSON.stringify(cart));

    // Play notification sound
    const audio = new Audio('/notification.mp3');
    audio.play().catch(() => {});

    alert('تمت إضافة اللعبة للسلة بنجاح!');

    // Navigate to cart page
    navigate('/cart');
  };

  const toggleFavorite = (game: Game) => {
    const savedFavorites = JSON.parse(localStorage.getItem('favorites') || '[]');
    const isFavorite = savedFavorites.some((fav: Game) => fav._id === game._id);

    if (isFavorite) {
      // Remove from favorites
      const updatedFavorites = savedFavorites.filter((fav: Game) => fav._id !== game._id);
      localStorage.setItem('favorites', JSON.stringify(updatedFavorites));
      setFavorites(updatedFavorites.map((fav: Game) => fav._id));
      showNotification('تم حذف المنتج من المفضلة', 'info');
    } else {
      // Add to favorites
      const updatedFavorites = [...savedFavorites, game];
      localStorage.setItem('favorites', JSON.stringify(updatedFavorites));
      setFavorites(updatedFavorites.map((fav: Game) => fav._id));
      showNotification('تمت إضافة المنتج للمفضلة', 'success');
    }
  };

  useEffect(() => {
    fetchGames();
  }, [filters, searchQuery]);

  const fetchGames = async () => {
    try {
      setLoading(true);

      // Use unified mock data
      let filteredGames = mockGames;

      // Apply filters
      if (filters.platform) {
        filteredGames = filteredGames.filter(game => game.platform === filters.platform);
      }

      // Apply search filter if exists
      if (searchQuery) {
        filteredGames = filteredGames.filter(game => 
          game.title.toLowerCase().includes(searchQuery.toLowerCase()) ||
          game.description.toLowerCase().includes(searchQuery.toLowerCase())
        );
      }

      setGames(filteredGames);
    } catch (error) {
      console.error('Error fetching games:', error);
      // Use mock data as fallback
      setGames(mockGames);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="min-h-screen" style={{ backgroundColor: '#0a0a0a' }}>
      {/* Hero Section */}
      <div className="relative bg-gradient-to-r from-red-900 to-black overflow-hidden">
        <div className="max-w-screen-2xl mx-auto px-4 sm:px-6 lg:px-8 py-16">
          <div className="text-center">
            {state.user ? (
              <>
                <h1 className="text-4xl md:text-6xl font-bold text-white mb-6">
                  أهلاً بك {formatDisplayName(state.user.firstName, state.user.lastName)}
                </h1>
                <p className="text-xl text-gray-300 mb-8 max-w-3xl mx-auto">
                  مرحباً بك في Alpha Store! استكشف أفضل الألعاب والعروض الحصرية
                </p>
              </>
            ) : (
              <>
                <h1 className="text-4xl md:text-6xl font-bold text-white mb-6">
                  Alpha Store
                </h1>
                <p className="text-xl text-gray-300 mb-8 max-w-3xl mx-auto">
                  أفضل متجر لبيع مفاتيح الألعاب الأصلية بأسعار تنافسية
                </p>
              </>
            )}
            <div className="flex flex-col sm:flex-row gap-4 justify-center">
              {!state.user && (
                <Link
                  to="/register"
                  className="btn-primary text-lg px-8 py-4"
                >
                  إنشاء حساب
                </Link>
              )}
              <button
                onClick={() => {
                  const productsSection = document.getElementById('products-section');
                  productsSection?.scrollIntoView({ behavior: 'smooth' });
                }}
                className="bg-gray-800 text-white px-8 py-4 rounded-lg hover:bg-gray-700 transition-colors text-lg"
              >
                استعرض الألعاب
              </button>
            </div>
          </div>
        </div>

        {/* Animated background elements */}
        <div className="absolute inset-0 overflow-hidden pointer-events-none">
          <div className="absolute top-20 left-10 w-72 h-72 bg-red-500 rounded-full mix-blend-multiply filter blur-xl opacity-20 animate-pulse"></div>
          <div className="absolute bottom-20 right-10 w-96 h-96 bg-red-600 rounded-full mix-blend-multiply filter blur-2xl opacity-10 animate-pulse"></div>
        </div>
      </div>

      {/* Featured Banner */}
      <div className="bg-gradient-to-r from-red-800 to-red-900 py-8">
        <div className="max-w-screen-2xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="card p-6 text-center">
            <div className="flex items-center justify-center mb-4">
              <div className="badge-new">جديد</div>
              <span className="text-white text-2xl font-bold ml-3">عروض حصرية</span>
            </div>
            <p className="text-gray-300 text-lg">
              خصم 20% على جميع مفاتيح Steam و Origin
            </p>
            <p className="text-red-400 font-semibold mt-2">
              لفترة محدودة - استخدم الكود: EN20
            </p>
          </div>
        </div>
      </div>

      {/* Filter Section */}
      <div className="max-w-screen-2xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
        <div className="bg-gradient-to-r from-gray-800 to-gray-900 rounded-2xl p-8 shadow-2xl border border-gray-700">
          <h2 className="text-3xl font-bold text-white mb-8 text-center bg-gradient-to-r from-red-400 to-red-600 bg-clip-text text-transparent">
            🔍 ابحث وتصفِّ
          </h2>
          <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
            <div className="group">
              <label className="block text-sm font-semibold text-gray-300 mb-3 flex items-center">
                <svg className="w-5 h-5 ml-2 text-red-500" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9.75 17L9 20l-1 1h8l-1-1-.75-3M3 13h18M5 17h14a2 2 0 002-2V5a2 2 0 00-2-2H5a2 2 0 00-2 2v10a2 2 0 002 2z" />
                </svg>
                المنصة
              </label>
              <select
                value={filters.platform}
                onChange={(e) => setFilters({...filters, platform: e.target.value})}
                className="w-full px-4 py-3 bg-gray-700 text-white rounded-lg border border-gray-600 focus:border-red-500 focus:ring-2 focus:ring-red-500 focus:outline-none transition-all duration-200 hover:bg-gray-600"
              >
                <option value="">🎮 كل المنصات</option>
                <option value="PC">💻 كمبيوتر</option>
                <option value="PlayStation">🎯 PlayStation</option>
                <option value="Xbox">🎮 Xbox</option>
                <option value="Nintendo Switch">🎲 Nintendo Switch</option>
                <option value="Mobile">📱 موبايل</option>
              </select>
            </div>

            <div className="group">
              <label className="block text-sm font-semibold text-gray-300 mb-3 flex items-center">
                <svg className="w-5 h-5 ml-2 text-red-500" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M3.055 11H5a2 2 0 012 2v1a2 2 0 002 2 2 2 0 012 2v2.945M8 3.935V5.5A2.5 2.5 0 0010.5 8h.5a2 2 0 012 2 2 2 0 104 0 2 2 0 012-2h1.064M15 20.488V18a2 2 0 012-2h3.064M21 12a9 9 0 11-18 0 9 9 0 0118 0z" />
                </svg>
                المنطقة
              </label>
              <select
                value={filters.region}
                onChange={(e) => setFilters({...filters, region: e.target.value})}
                className="w-full px-4 py-3 bg-gray-700 text-white rounded-lg border border-gray-600 focus:border-red-500 focus:ring-2 focus:ring-red-500 focus:outline-none transition-all duration-200 hover:bg-gray-600"
              >
                <option value="">🌍 كل المناطق</option>
                <option value="Global">🌐 عالمي</option>
                <option value="North America">🇺🇸 أمريكا الشمالية</option>
                <option value="Europe">🇪🇺 أوروبا</option>
                <option value="Asia">🏯 آسيا</option>
                <option value="Middle East">🕌 الشرق الأوسط</option>
              </select>
            </div>

            <div className="group">
              <label className="block text-sm font-semibold text-gray-300 mb-3 flex items-center">
                <svg className="w-5 h-5 ml-2 text-red-500" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 8c-1.657 0-3 .895-3 2s1.343 2 3 2 3 .895 3 2-1.343 2-3 2m0-8c1.11 0 2.08.402 2.599 1M12 8V7m0 1v8m0 0v1m0-1c-1.11 0-2.08-.402-2.599-1M21 12a9 9 0 11-18 0 9 9 0 0118 0z" />
                </svg>
                نطاق السعر
              </label>
              <select
                value={filters.priceRange}
                onChange={(e) => setFilters({...filters, priceRange: e.target.value})}
                className="w-full px-4 py-3 bg-gray-700 text-white rounded-lg border border-gray-600 focus:border-red-500 focus:ring-2 focus:ring-red-500 focus:outline-none transition-all duration-200 hover:bg-gray-600"
              >
                <option value="all">💰 كل الأسعار</option>
                <option value="0-25">🪙 0 - 25$</option>
                <option value="25-50">💵 25 - 50$</option>
                <option value="50-100">💎 50 - 100$</option>
                <option value="100+">🏆 أكثر من 100$</option>
              </select>
            </div>
          </div>
        </div>
      </div>

      {/* Products Grid */}
      <div id="products-section" className="max-w-screen-2xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
        <div className="text-center mb-12">
          <h2 className="text-4xl font-bold text-white mb-4 bg-gradient-to-r from-red-400 via-red-500 to-red-600 bg-clip-text text-transparent">
            🎮 منتجاتنا
          </h2>
          <p className="text-gray-400 text-lg">اكتشف أفضل الألعاب والعروض الحصرية</p>
        </div>

        {loading ? (
          <div className="text-center py-16">
            <div className="inline-block animate-spin rounded-full h-12 w-12 border-b-2 border-red-600"></div>
            <p className="text-gray-400 mt-4">جاري التحميل...</p>
          </div>
        ) : (
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-8">
            {Array.isArray(games) && games.map((game) => (
              <div key={game._id} className="group">
                {/* Product Card - Professional Clean Design */}
                <div className="bg-gradient-to-br from-gray-800 to-gray-900 rounded-2xl overflow-hidden shadow-lg hover:shadow-2xl transition-all duration-300 transform hover:scale-105 border border-gray-700">
                  {/* Game Image Section */}
                  <div className="relative h-64 overflow-hidden">
                    {game.images && game.images.length > 0 ? (
                      <>
                        <img
                          src={game.images[0]}
                          alt=""  /* Empty alt to prevent text display */
                          className="w-full h-full object-cover group-hover:scale-110 transition-transform duration-700"
                        />
                        {/* Minimal Gradient Overlay - Only at very bottom for clean separation */}
                        <div className="absolute inset-0 bg-gradient-to-t from-black/40 via-transparent via-transparent to-transparent"></div>

                        {/* Discount Badge - Top Right Corner - Highest z-index */}
                        {game.discount && (
                          <div className="absolute top-3 right-3 z-30 bg-red-500 text-white px-3 py-1.5 rounded-full text-sm font-bold shadow-xl border-2 border-red-600">
                            -{game.discount}%
                          </div>
                        )}

                        {/* Heart Icon - Top Left Corner - Highest z-index */}
                        <button 
                          onClick={() => toggleFavorite(game)}
                          className={`absolute top-3 left-3 z-30 p-2 rounded-full shadow-xl transform hover:scale-110 transition-all duration-200 border-2 ${
                            favorites.includes(game._id) 
                              ? 'bg-red-500 border-red-600' 
                              : 'bg-white/95 border-white hover:bg-red-50'
                          }`}
                        >
                          <svg 
                            className={`w-5 h-5 transition-colors duration-200 ${
                              favorites.includes(game._id) 
                                ? 'text-white' 
                                : 'text-gray-600 hover:text-red-500'
                            }`} 
                            fill={favorites.includes(game._id) ? 'currentColor' : 'none'} 
                            stroke="currentColor" 
                            viewBox="0 0 24 24"
                          >
                            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4.318 6.318a4.5 4.5 0 000 6.364L12 20.364l7.682-7.682a4.5 4.5 0 00-6.364-6.364L12 7.636l-1.318-1.318a4.5 4.5 0 00-6.364 0z" />
                          </svg>
                        </button>
                      </>
                    ) : (
                      <div className="h-full bg-gray-700 flex items-center justify-center">
                        <div className="text-center">
                          <svg className="w-12 h-12 text-gray-500 mx-auto mb-2" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z" />
                          </svg>
                          <span className="text-gray-400 text-sm">لا توجد صور</span>
                        </div>
                      </div>
                    )}
                  </div>

                  {/* Content Section - Clean Hierarchy */}
                  <div className="p-6">
                    {/* Title - Large and Clear - ONLY TITLE HERE */}
                    <h3 className="text-xl font-bold text-white mb-3 leading-tight">
                      {game.title}
                    </h3>

                    {/* Description - Short */}
                    <p className="text-gray-400 text-sm mb-4 line-clamp-2 leading-relaxed">
                      {game.description}
                    </p>

                    {/* Platform & Region Badges - Single Line */}
                    <div className="flex items-center space-x-2 mb-5">
                      <span className="bg-gray-700 text-gray-300 px-3 py-1 rounded-lg text-xs font-medium border border-gray-600">
                        🎮 {game.platform}
                      </span>
                      <span className="bg-gray-700 text-gray-300 px-3 py-1 rounded-lg text-xs font-medium border border-gray-600">
                        🌍 {game.region}
                      </span>
                    </div>

                    {/* Price Section - Most Important */}
                    <div className="flex items-end justify-between mb-5">
                      <div className="flex items-baseline space-x-2">
                        {game.originalPrice && (
                          <span className="text-gray-500 line-through text-lg">
                            ${game.originalPrice}
                          </span>
                        )}
                        <span className="text-green-400 font-bold text-3xl">
                          ${game.price}
                        </span>
                      </div>

                      {game.discount && (
                        <span className="bg-green-600/20 text-green-400 px-2 py-1 rounded-lg text-xs font-medium border border-green-600/50">
                          Save {game.discount}%
                        </span>
                      )}
                    </div>

                    {/* Add to Cart Button - Full Width */}
                    <button
                      onClick={() => addToCart(game)}
                      className="w-full bg-red-500 hover:bg-red-600 text-white px-6 py-3 rounded-xl font-semibold text-lg transition-all duration-200 transform hover:scale-105 shadow-lg hover:shadow-red-500/25"
                    >
                      أضف للسلة
                    </button>
                  </div>
                </div>
              </div>
            ))}
          </div>
        )}

        {!loading && games.length === 0 && (
          <div className="text-center py-16 bg-gray-800 rounded-2xl shadow-lg border border-gray-700">
            <div className="w-20 h-20 bg-gray-700 rounded-full flex items-center justify-center mx-auto mb-4">
              <svg className="w-10 h-10 text-gray-400" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M20 13V6a2 2 0 00-2-2H6a2 2 0 00-2 2v7m16 0v5a2 2 0 01-2 2H6a2 2 0 01-2-2v-5m16 0h-2.586a1 1 0 00-.707.293l-2.414 2.414a1 1 0 01-.707.293h-3.172a1 1 0 01-.707-.293l-2.414-2.414A1 1 0 006.586 13H4" />
              </svg>
            </div>
            <h3 className="text-xl font-semibold text-white mb-2">لا توجد منتجات متاحة حالياً</h3>
            <p className="text-gray-400 mb-6">لم يتم العثور على منتجات مطابقة لبحثك</p>
            <button
              onClick={() => setFilters({ platform: '', region: '', priceRange: 'all' })}
              className="bg-red-500 hover:bg-red-600 text-white px-6 py-3 rounded-lg font-semibold transition-colors"
            >
              إعادة تعيين الفلاتر
            </button>
          </div>
        )}
      </div>

      {/* Footer */}
      <footer className="bg-black border-t border-gray-800 py-8 mt-16">
        <div className="max-w-screen-2xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="grid grid-cols-1 md:grid-cols-4 gap-8">
            <div>
              <h3 className="text-white font-semibold mb-4">Alpha Store</h3>
              <p className="text-gray-400 text-sm">
                أفضل متجر لبيع مفاتيح الألعاب الأصلية
              </p>
            </div>

            <div>
              <h3 className="text-white font-semibold mb-4">روابط سريعة</h3>
              <ul className="space-y-2">
                <li><Link to="/" className="text-gray-400 hover:text-white text-sm transition-colors">الرئيسية</Link></li>
                <li><Link to="/games" className="text-gray-400 hover:text-white text-sm transition-colors">المنتجات</Link></li>
                <li><Link to="/cart" className="text-gray-400 hover:text-white text-sm transition-colors">طلباتي</Link></li>
              </ul>
            </div>

            <div>
              <h3 className="text-white font-semibold mb-4">الدعم</h3>
              <ul className="space-y-2">
                <li><a href="#" className="text-gray-400 hover:text-white text-sm transition-colors">مركز المساعدة</a></li>
                <li><a href="#" className="text-gray-400 hover:text-white text-sm transition-colors">اتصل بنا</a></li>
                <li><a href="#" className="text-gray-400 hover:text-white text-sm transition-colors">الشروط والأحكام</a></li>
              </ul>
            </div>

            <div>
              <h3 className="text-white font-semibold mb-4">تابعنا</h3>
              <div className="flex space-x-4">
                <a href="https://www.instagram.com/alpha_store.jo/" target="_blank" rel="noopener noreferrer" className="text-gray-400 hover:text-white transition-colors">
                  <svg className="w-6 h-6" fill="currentColor" viewBox="0 0 24 24">
                    <path d="M12 2.163c3.204 0 3.584.012 4.85.07 3.252.148 4.771 1.691 4.919 4.919.058 1.265.069 1.645.069 4.849 0 3.205-.012 3.584-.069 4.849-.149 3.225-1.664 4.771-4.919 4.919-1.266.058-1.644.07-4.85.07-3.204 0-3.584-.012-4.849-.07-3.26-.149-4.771-1.699-4.919-4.92-.058-1.265-.07-1.644-.07-4.849 0-3.204.013-3.583.07-4.849.149-3.227 1.664-4.771 4.919-4.919 1.266-.057 1.645-.069 4.849-.069zm0-2.163c-3.259 0-3.667.014-4.947.072-4.358.2-6.78 2.618-6.98 6.98-.059 1.281-.073 1.689-.073 4.948 0 3.259.014 3.668.072 4.948.2 4.358 2.618 6.78 6.98 6.98 1.281.058 1.689.072 4.948.072 3.259 0 3.668-.014 4.948-.072 4.354-.2 6.782-2.618 6.979-6.98.059-1.28.073-1.689.073-4.948 0-3.259-.014-3.667-.072-4.947-.196-4.354-2.617-6.78-6.979-6.98-1.281-.059-1.69-.073-4.949-.073zM5.838 12a6.162 6.162 0 1112.324 0 6.162 6.162 0 01-12.324 0zM12 16a4 4 0 110-8 4 4 0 010 8zm4.965-10.405a1.44 1.44 0 112.881.001 1.44 1.44 0 01-2.881-.001z"/>
                  </svg>
                </a>
              </div>
            </div>
          </div>

          <div className="border-t border-gray-800 mt-8 pt-8 text-center">
            <p className="text-gray-400 text-sm">
              © 2026 Alpha Store. جميع الحقوق محفوظة.
